 1→import { SupportedNetworks } from '@modules/networks/types';
 2→import { UUID } from 'crypto';
 3→import { ColumnType, Generated } from 'kysely';
 4→
 5→export enum DepositStatus {
 6→  PENDING = 'PENDING',
 7→  COMPLETED = 'COMPLETED',
 8→  FAILED = 'FAILED',
 9→  EXPIRED = 'EXPIRED',
10→}
11→
12→export interface DepositEntity {
13→  id: Generated<UUID>;
14→  tenantAccountId: UUID;
15→  currencyCode: string;
16→  currencyNetwork: SupportedNetworks;
17→  amountExpected: number;
18→  strictAmountExpected: boolean;
19→  actuallyReceivedAmount: number | null;
20→  actuallyReceivedAmountUSD: number | null;
21→  // Commision
22→  commissionAmount: number;
23→  // description of the deposit that user will see in the payment link. Example: "Deposit to example.com"
24→  description: string;
25→  status: DepositStatus;
26→  paymentLink: string;
27→  paymentLinkExpiresAt: ColumnType<Date, Date, never>;
28→  paymentLinkUsedAt: Date | null;
29→  paymentLinkUsedIp: ColumnType<string, string, string> | null;
30→  paymentLinkUsedUserAgent: string | null;
31→  paymentLinkUsedDevice: string | null;
32→  paymentLinkUsedDeviceType: string | null;
33→  // Deposit pool account ID (required - all deposits use pool accounts)
34→  depositPoolAccountId: UUID | null;
35→  // Transaction hash of the deposit transaction (when user sent funds to deposit address)
36→  depositTransactionHash: string | null;
37→  createdAt: ColumnType<Date, undefined, never>;
38→  updatedAt: ColumnType<Date, undefined, never>;
39→}
