 5→import { BullModule } from '@nestjs/bullmq';
 6→import { ConfigModule } from '@nestjs/config';
 7→import { networksConfigs } from '@configs/networks.configs';
 8→import {
 9→  DEPOSIT_QUEUE_NAME,
10→  DEPOSIT_FLOW_PRODUCER_NAME,
11→  DEPOSIT_POOL_QUEUE_NAME,
12→} from './constant';
13→import { DepositProcessor } from './processors/deposit.processor';
14→import { DepositService } from './services/deposit.service';
15→import { DepositPoolService } from './services/deposit-pool.service';
16→import { DepositController } from './controllers/deposit.controller';
17→import { DepositeOutboxProcessor } from './processors/deposite-outbox.processor';
18→import { DepositPoolMonitoringService } from './services/deposit-pool.monitoring.service';
19→import { DepositPoolProcessor } from './processors/deposit-pool.processor';
20→
21→@Module({
22→  imports: [
23→    BalanceModule,
24→    NetworksModule,
25→    CurrencyModule,
26→    ConfigModule.forFeature(networksConfigs),
27→    BullModule.registerQueue({
28→      name: DEPOSIT_QUEUE_NAME,
29→      defaultJobOptions: {
30→        attempts: 3,
31→        backoff: {
32→          type: 'exponential',
33→          delay: 10_000,
34→        },
35→        removeOnComplete: true,
36→        removeOnFail: false,
37→      },
38→    }),
39→    BullModule.registerQueue({
40→      name: DEPOSIT_POOL_QUEUE_NAME,
41→      defaultJobOptions: {
42→        attempts: 2,
43→        backoff: {
44→          type: 'exponential',
45→          delay: 10_000,
46→        },
47→        removeOnComplete: true,
48→        removeOnFail: true,
49→      },
50→    }),
51→    BullModule.registerFlowProducerAsync({
52→      name: DEPOSIT_FLOW_PRODUCER_NAME,
53→    }),
54→  ],
55→  controllers: [DepositController],
56→  providers: [
57→    DepositProcessor,
58→    DepositService,
59→    DepositPoolService,
