  1→import {
  2→  Inject,
  3→  Injectable,
  4→  Logger,
  5→  BadRequestException,
  6→} from '@nestjs/common';
  7→import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
  8→import { Db } from '@shared/database/types';
  9→import { UUID } from 'crypto';
 10→import { SupportedNetworks } from '@modules/networks/types/network.type';
 11→import { NetworksService } from '@modules/networks/services/networks.service';
 12→import { OutstandingTronAccountService } from '@modules/networks/tron/services/outstanding-tron.account';
 13→import { ControlledTransaction, Selectable } from 'kysely';
 14→import { Database } from '../../../db/database.type';
 15→import { DepositPoolAccountEntity } from '@entities/balance.entity';
 16→import { networksConfigs } from '@configs/networks.configs';
 17→import { ConfigType } from '@nestjs/config';
 18→
 19→@Injectable()
 20→export class DepositPoolService {
 21→  private readonly logger = new Logger(DepositPoolService.name);
 22→
 23→  constructor(
 24→    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
 25→    private readonly networksService: NetworksService,
 26→    private readonly outstandingTronAccountService: OutstandingTronAccountService,
 27→    @Inject(networksConfigs.KEY)
 28→    private readonly networksConfig: ConfigType<typeof networksConfigs>,
 29→  ) {
 30→    //this.adjustPoolCount(SupportedNetworks.TRON);
 31→    //this.adjustPoolCount(SupportedNetworks.ETHEREUM);
 32→  }
 33→
 34→  /**
 35→   * Creates a global pool of 3 accounts for a network
 36→   * Accounts are activated using the outstanding account service
 37→   */
 38→  async adjustPoolCount(
 39→    network: SupportedNetworks,
 40→    targetCount: number = 2,
 41→  ): Promise<void> {
 42→    const trx = await this.db.startTransaction().execute();
 43→
 44→    try {
 45→      // Check if pool already exists
 46→      const existingPoolCount = await trx
 47→        .selectFrom('depositPoolAccount')
 48→        .select(({ fn }) => [fn.count<number>('id').as('count')])
 49→        .where('network', '=', network)
 50→        .executeTakeFirst();
 51→
 52→      const countToCreate = targetCount - (existingPoolCount.count ?? 0);
 53→      if (countToCreate <= 0) {
 54→        this.logger.log({
 55→          message: 'Pool already has enough accounts',
 56→          network,
 57→          targetCount,
 58→          existingPoolCount: existingPoolCount.count,
 59→        });
 60→        return;
 61→      }
 62→
 63→      // Create 3 pool accounts
 64→      const poolAccounts = [];
 65→      const addresses: string[] = [];
 66→      for (let i = 0; i < countToCreate; i++) {
 67→        const networkAccount =
 68→          await this.networksService.createAccount(network);
 69→
 70→        // Create pool account record with address and privateKey directly
 71→        const poolAccount = await trx
 72→          .insertInto('depositPoolAccount')
 73→          .values({
 74→            address: networkAccount.address,
 75→            privateKey: networkAccount.privateKey,
 76→            network: network,
 77→          })
 78→          .returningAll()
 79→          .executeTakeFirstOrThrow();
 80→
 81→        poolAccounts.push(poolAccount);
 82→        addresses.push(networkAccount.address);
 83→      }
 84→
 85→      // Activate accounts using outstanding account service (for Tron)
 86→      if (network === SupportedNetworks.TRON) {
 87→        await this.outstandingTronAccountService.activateAccounts(addresses);
 88→      }
 89→
 90→      await trx.commit().execute();
 91→
 92→      this.logger.log({
 93→        message: 'Pool created',
 94→        network,
 95→        accountCount: poolAccounts.length,
 96→      });
 97→    } catch (error) {
 98→      await trx.rollback().execute();
 99→      this.logger.error({ error, message: 'Failed to create pool', network });
100→      throw error;
101→    }
102→  }
103→
104→  /**
105→   * Gets an available pool account row (FOR UPDATE) within an existing transaction.
106→   * This is used when the caller (e.g. DepositService) manages the full transaction lifecycle.
107→   * Returns an account that is not locked for the given currency.
108→   */
109→  async getAndLockAvailablePoolAccount(
110→    trx: ControlledTransaction<Database, []>,
111→    options: {
112→      network: SupportedNetworks;
113→      currencyId: UUID;
114→    },
115→  ): Promise<{ id: UUID; address: string } | undefined> {
116→    // Get all pool accounts for the network
117→    const allPoolAccounts = await trx
118→      .selectFrom('depositPoolAccount')
119→      .forUpdate()
120→      .select(['id', 'address'])
121→      .where('network', '=', options.network)
122→      .execute();
123→
124→    // Get all pool account IDs that are locked for this currency
125→    const lockedPoolAccountIds = await trx
126→      .selectFrom('depositPoolAccountLocks')
127→      .select(['depositPoolAccountId'])
128→      .where('currencyId', '=', options.currencyId)
129→      .execute();
130→
131→    const lockedIdsSet = new Set(
132→      lockedPoolAccountIds.map((lock) => lock.depositPoolAccountId),
133→    );
134→
135→    // Find the first available account that is not locked for this currency
136→    const availableAccount = allPoolAccounts.find(
137→      (account) => !lockedIdsSet.has(account.id),
138→    );
139→
140→    if (!availableAccount) {
141→      throw new BadRequestException(
142→        `No available pool account found for ${options.network} network. All accounts may be in use.`,
143→      );
144→    }
145→
146→    // Lock the row with FOR UPDATE to prevent concurrent access
147→    await this.lockPoolAccount(availableAccount.id, options.currencyId, trx);
148→
149→    return { id: availableAccount.id, address: availableAccount.address };
150→  }
151→
152→  async setDepositIdOnLockRecord(
153→    depositId: UUID,
154→    poolAccountId: UUID,
155→    currencyId: UUID,
156→    trx: ControlledTransaction<Database, []>,
157→  ): Promise<void> {
158→    await trx
159→      .updateTable('depositPoolAccountLocks')
160→      .set({
161→        depositId: depositId,
162→      })
163→      .where('depositPoolAccountId', '=', poolAccountId)
164→      .where('currencyId', '=', currencyId)
165→      .execute();
166→  }
167→
168→  /**
169→   * Locks a pool account to a specific currency and deposit
170→   * This is used when the account has already been selected via getAvailablePoolAccountForUpdate
171→   */
172→  async lockPoolAccount(
173→    poolAccountId: UUID,
174→    currencyId: UUID,
175→    trx: ControlledTransaction<Database, []>,
176→  ): Promise<void> {
177→    const existingLock = await trx
178→      .selectFrom('depositPoolAccountLocks')
179→      .selectAll()
180→      .where('depositPoolAccountId', '=', poolAccountId)
181→      .where('currencyId', '=', currencyId)
182→      .executeTakeFirst();
183→    if (existingLock) {
184→      throw new BadRequestException(
185→        `Pool account ${poolAccountId} already locked`,
186→      );
187→    }
188→
189→    await trx
190→      .insertInto('depositPoolAccountLocks')
191→      .values({
192→        depositPoolAccountId: poolAccountId,
193→        currencyId: currencyId,
194→      })
195→      .execute();
196→
197→    this.logger.log({
198→      message: 'Pool account locked',
199→      poolAccountId,
200→      currencyId,
201→    });
202→  }
203→
204→  /**
205→   * Unlocks a pool account after deposit finished
206→   */
207→  async unlockPoolAccount(
208→    poolAccountId: UUID,
209→    currencyId: UUID,
210→    _trx?: ControlledTransaction<Database, []>,
211→  ): Promise<void> {
212→    const trx = _trx ?? (await this.db.startTransaction().execute());
213→    await trx
214→      .deleteFrom('depositPoolAccountLocks')
215→      .where('depositPoolAccountId', '=', poolAccountId)
216→      .where('currencyId', '=', currencyId)
217→      .execute();
218→
219→    this.logger.log({ message: 'Pool account unlocked', poolAccountId });
220→    if (!_trx) {
221→      await trx.commit().execute();
222→    }
223→  }
224→
225→  /**
226→   * Gets pool account by ID with address and private key
227→   */
228→  async getAccountById(
229→    poolAccountId: UUID,
230→  ): Promise<Selectable<DepositPoolAccountEntity>> {
231→    const result = await this.db
232→      .selectFrom('depositPoolAccount')
233→      .selectAll()
234→      .where('id', '=', poolAccountId)
235→      .executeTakeFirstOrThrow();
236→
237→    return result;
238→  }
239→}
