 79→            throw new BadRequestException(
 80→              'Solana network is not supported yet',
 81→            );
 82→          default:
 83→            throw new BadRequestException('Unsupported network');
 84→        }
 85→      } else {
 86→        // Token currency - find currency by contract address
 87→        const currencies = await this.currencyService.getCurrencies({});
 88→        const tokenCurrency = currencies.find(
 89→          (c) => c.contractAddress === contractAddress && c.network === network,
 90→        );
 91→
 92→        if (!tokenCurrency) {
 93→          throw new BadRequestException(
 94→            `Currency not found for contract address: ${contractAddress}`,
 95→          );
 96→        }
 97→
 98→        switch (network) {
 99→          case SupportedNetworks.TRON:
100→            balance = await this.tronNetworkService.getTokenBalance(
101→              address,
102→              tokenCurrency.code,
103→            );
104→            break;
105→          case SupportedNetworks.ETHEREUM:
106→            balance = await this.ethereumNetworkService.getTokenBalance(
107→              address,
108→              contractAddress,
109→              tokenCurrency.decimalPlaces,
110→            );
111→            break;
112→          case SupportedNetworks.SOLANA:
113→            throw new BadRequestException(
114→              'Solana network is not supported yet',
115→            );
116→          default:
117→            throw new BadRequestException('Unsupported network');
118→        }
119→      }
120→
121→      const amount = parseFloat(balance);
122→      return {
123→        found: amount > 0,
124→        amount: balance,
125→      };
126→    } catch (error) {
